// =====================================================
// ENTRADA VINDO DO SET
// =====================================================
const baseServicos = $json.base_servicos || [];
const preferenciaAtendimento = $json.preferencia_atendimento || {};
const preferenciaData = $json.preferencia_data || {};
const preferenciaPeriodo = $json.preferencia_periodo || {};
const horariosManha = $json.horarios_manha || {};
const horariosTarde = $json.horarios_tarde || {};

// =====================================================
// GERADOR
// =====================================================
const output = [];

// =====================================================
// NÍVEL 1: PEÇAS ÚNICAS
// =====================================================
const pecasUnicas = {};

for (const servico of baseServicos) {
  const codigoPeca = String(servico.id_produto);

  if (!pecasUnicas[codigoPeca]) {
    pecasUnicas[codigoPeca] = {
      codigo: codigoPeca,
      nivel: 1,
      id_produto: servico.id_produto,
      piece_type: servico.piece_type,
      id_servico: null,
      service_type: null,
      preco: null,
      acao_codigo: null,
      acao: null,
      data_codigo: null,
      preferencia_data: null,
      periodo_codigo: null,
      periodo: null,
      horario_codigo: null,
      horario: null,
      significado: `${servico.piece_type}`
    };
  }
}

output.push(...Object.values(pecasUnicas));

// =====================================================
// NÍVEL 2 A 6
// =====================================================
for (const servico of baseServicos) {
  const codigoServico = String(servico.id_servico);

  // ---------------------------------
  // NÍVEL 2: PEÇA + SERVIÇO
  // ---------------------------------
  output.push({
    codigo: codigoServico,
    nivel: 2,
    id_produto: servico.id_produto,
    piece_type: servico.piece_type,
    id_servico: servico.id_servico,
    service_type: servico.service_type,
    preco: servico.preco ?? null,
    acao_codigo: null,
    acao: null,
    data_codigo: null,
    preferencia_data: null,
    periodo_codigo: null,
    periodo: null,
    horario_codigo: null,
    horario: null,
    significado: `${servico.piece_type} > ${servico.service_type}`
  });

  // ---------------------------------
  // NÍVEL 3: AÇÃO
  // ---------------------------------
  for (const [codAcao, nomeAcao] of Object.entries(preferenciaAtendimento)) {
    const codigoAcao = `${codigoServico}${codAcao}`;

    output.push({
      codigo: codigoAcao,
      nivel: 3,
      id_produto: servico.id_produto,
      piece_type: servico.piece_type,
      id_servico: servico.id_servico,
      service_type: servico.service_type,
      preco: servico.preco ?? null,
      acao_codigo: codAcao,
      acao: nomeAcao,
      data_codigo: null,
      preferencia_data: null,
      periodo_codigo: null,
      periodo: null,
      horario_codigo: null,
      horario: null,
      significado: `${servico.piece_type} > ${servico.service_type} > ${String(nomeAcao).toLowerCase()}`
    });

    // Se for atendimento no WhatsApp, para aqui
    if (nomeAcao !== "AGENDAR_VISITA") {
      continue;
    }

    // ---------------------------------
    // NÍVEL 4: DATA
    // ---------------------------------
    for (const [codData, nomeData] of Object.entries(preferenciaData)) {
      const codigoData = `${codigoAcao}${codData}`;

      output.push({
        codigo: codigoData,
        nivel: 4,
        id_produto: servico.id_produto,
        piece_type: servico.piece_type,
        id_servico: servico.id_servico,
        service_type: servico.service_type,
        preco: servico.preco ?? null,
        acao_codigo: codAcao,
        acao: nomeAcao,
        data_codigo: codData,
        preferencia_data: nomeData,
        periodo_codigo: null,
        periodo: null,
        horario_codigo: null,
        horario: null,
        significado: `${servico.piece_type} > ${servico.service_type} > ${String(nomeAcao).toLowerCase()} > ${String(nomeData).toLowerCase()}`
      });

      // ---------------------------------
      // NÍVEL 5: PERÍODO
      // ---------------------------------
      for (const [codPeriodo, nomePeriodo] of Object.entries(preferenciaPeriodo)) {
        const codigoPeriodo = `${codigoData}${codPeriodo}`;

        output.push({
          codigo: codigoPeriodo,
          nivel: 5,
          id_produto: servico.id_produto,
          piece_type: servico.piece_type,
          id_servico: servico.id_servico,
          service_type: servico.service_type,
          preco: servico.preco ?? null,
          acao_codigo: codAcao,
          acao: nomeAcao,
          data_codigo: codData,
          preferencia_data: nomeData,
          periodo_codigo: codPeriodo,
          periodo: nomePeriodo,
          horario_codigo: null,
          horario: null,
          significado: `${servico.piece_type} > ${servico.service_type} > ${String(nomeAcao).toLowerCase()} > ${String(nomeData).toLowerCase()} > ${String(nomePeriodo).toLowerCase()}`
        });

        // ---------------------------------
        // NÍVEL 6: HORÁRIOS
        // ---------------------------------
        const mapaHorarios = nomePeriodo === "MANHA" ? horariosManha : horariosTarde;

        for (const [codHorario, hora] of Object.entries(mapaHorarios)) {
          const codigoFinal = `${codigoPeriodo}${codHorario}`;

          output.push({
            codigo: codigoFinal,
            nivel: 6,
            id_produto: servico.id_produto,
            piece_type: servico.piece_type,
            id_servico: servico.id_servico,
            service_type: servico.service_type,
            preco: servico.preco ?? null,
            acao_codigo: codAcao,
            acao: nomeAcao,
            data_codigo: codData,
            preferencia_data: nomeData,
            periodo_codigo: codPeriodo,
            periodo: nomePeriodo,
            horario_codigo: codHorario,
            horario: hora,
            significado: `${servico.piece_type} > ${servico.service_type} > ${String(nomeAcao).toLowerCase()} > ${String(nomeData).toLowerCase()} > ${String(nomePeriodo).toLowerCase()} > ${hora}`
          });
        }
      }
    }
  }
}

// =====================================================
// RETORNO
// =====================================================
return output.map(item => ({ json: item }));

const items = $input.all();

function normalizeText(value) {
  return String(value ?? "")
    .trim()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");
}

function cleanText(value) {
  return String(value ?? "").trim();
}

const uniqueRows = new Map();

for (const item of items) {
  const row = item.json;

  const pieceType = cleanText(row.piece_type);
  const idProduto = row.id_produto;
  const serviceType = cleanText(row.service_type);
  const idServico = row.id_servico;

  // só entra se tiver peça e serviço
  if (!pieceType || !serviceType) continue;
  if (idProduto === null || idProduto === undefined) continue;
  if (idServico === null || idServico === undefined) continue;

  // chave única por peça + serviço
  const key = [
    String(idProduto),
    normalizeText(pieceType),
    String(idServico),
    normalizeText(serviceType)
  ].join("__");

  if (!uniqueRows.has(key)) {
    uniqueRows.set(key, {
      piece_type: pieceType,
      id_produto: Number(idProduto),
      service_type: serviceType,
      id_servico: Number(idServico),
    });
  }
}

return Array.from(uniqueRows.values()).map(row => ({
  json: row
}));

