// Pega o item do node "resposta concatenada"
const row = $('resposta concatenada1').first().json;

// Pega messages corretos dentro da sessão
let messages = row.session?.messages;
if (!Array.isArray(messages)) {
  messages = [];
}

// Próxima stage após envio da welcome
const next_stage = "collect_context";

// Pergunta inicial
const reply = "Olá! 😊 Ateliê Careliz ✂️🧵\n\nQual peça você deseja ajustar?\n\nDigite o número correspondente:\n\n1️⃣ Calça\n2️⃣ Camisa\n3️⃣ Vestido\n4️⃣ Saia\n5️⃣ Shorts\n6️⃣ Jaqueta\n7️⃣ Outro\n\n✍️ Responda apenas com o número.";

// Adiciona resposta do assistente ao histórico existente
messages.push({
  role: "assistant",
  text: reply,
  ts: new Date().toISOString()
});

// Atualiza sessão
const session = {
  ...row.session,
  messages,
  stage: next_stage,
  updated_at: new Date().toISOString()
};

return [
  {
    json: {
      ...row,
      action: "reply",
      reply,
      next_stage,
      session
    }
  }
];

const items = $input.all();

// pega o primeiro item do node "calça"
const baseItems = $items("calça1");
const baseRow = Array.isArray(baseItems) && baseItems.length > 0
  ? baseItems[0].json
  : {};

// peça
const pieceType = items[0]?.json?.piece_type || baseRow["peça"] || "peça";

// formatação bonita
function formatLabel(text) {
  return String(text || "")
    .replaceAll("_", " ")
    .replace(/\b\w/g, l => l.toUpperCase());
}

// emojis
const baseEmojis = ["1️⃣","2️⃣","3️⃣","4️⃣","5️⃣","6️⃣","7️⃣","8️⃣","9️⃣","🔟"];

function getEmoji(index) {
  const number = index + 1;

  if (number <= 10) {
    return baseEmojis[index];
  }

  return String(number)
    .split("")
    .map(d => baseEmojis[Number(d) - 1] || d)
    .join("");
}

// remove duplicados por service_type
const uniqueMap = new Map();

for (const item of items) {
  const row = item.json;
  const serviceKey = String(row.service_type || "").trim().toLowerCase();

  if (!serviceKey) continue;

  // mantém apenas a primeira ocorrência de cada serviço
  if (!uniqueMap.has(serviceKey)) {
    uniqueMap.set(serviceKey, row);
  }
}

// transforma em array e ordena
const services = Array.from(uniqueMap.values()).sort(
  (a, b) => Number(a.id_servico) - Number(b.id_servico)
);

// lista dos serviços
const serviceList = services
  .map((s, index) => `${getEmoji(index)} ${formatLabel(s.service_type)}`)
  .join("\n\n");

// mensagem final
const message = `Qual ajuste você quer fazer na sua ${pieceType}?

${serviceList}

━━━━━━━━━━━━━━━
📩 Como responder:
Digite apenas o número da opção desejada.
━━━━━━━━━━━━━━━`;

return [
  {
    json: {
      ...baseRow,
      message
    }
  }
];

const row = items[0].json;

// ================================
// 1) TENTAR LER DO NOVO FORMATO DO AGENTE
// ================================
const output = row.output ?? {};

const agentPieceId =
  output.piece_id !== undefined && output.piece_id !== null
    ? Number(output.piece_id)
    : null;

const agentServiceType =
  output.service_type !== undefined && output.service_type !== null
    ? String(output.service_type).trim()
    : null;

const agentServiceId =
  output.service_id !== undefined && output.service_id !== null
    ? Number(output.service_id)
    : null;

// se o agente já trouxe dados estruturados, prioriza eles
if (agentPieceId !== null || agentServiceType || agentServiceId !== null) {
  return [
    {
      json: {
        ...row,
        id_produto: agentPieceId,
        opcao_servico: agentServiceType,
        id_servico: agentServiceId
      }
    }
  ];
}

// ================================
// 2) FORMATO ANTIGO (FLUXO LEGADO)
// ================================

// mensagens da sessão
const messages = Array.isArray(row.session?.messages) ? row.session.messages : [];

// só mensagens do usuário
const userMessages = messages
  .filter(m => m.role === "user" && m.text != null)
  .map(m => String(m.text).trim())
  .filter(Boolean);

// função para extrair número da mensagem
function extractNumber(text) {
  const match = String(text).match(/\d+/);
  return match ? Number(match[0]) : null;
}

// 2ª mensagem do usuário = escolha da peça
const secondUserMessage = userMessages[1] ?? null;
const id_produto = secondUserMessage ? extractNumber(secondUserMessage) : null;

// 3ª mensagem do usuário = escolha do serviço
const thirdUserMessage = userMessages[2] ?? null;
const serviceChoice = thirdUserMessage ? extractNumber(thirdUserMessage) : null;

// opcao_servico e id_servico só existem quando já houver 2ª e 3ª mensagem do usuário
let opcao_servico = null;
let id_servico = null;

if (id_produto !== null && serviceChoice !== null) {
  opcao_servico = Number(`${id_produto}${serviceChoice}`);
  id_servico = opcao_servico;
}

return [
  {
    json: {
      ...row,
      id_produto,
      opcao_servico,
      id_servico
    }
  }
];

const messages = $json.session?.messages || [];

// ================================
// PEGAR piece_id e service_id
// ================================
const pieceId =
  $json.output?.piece_id !== undefined && $json.output?.piece_id !== null
    ? String($json.output.piece_id)
    : "";

const serviceId =
  $json.output?.service_id !== undefined && $json.output?.service_id !== null
    ? String($json.output.service_id)
    : "";

// ================================
// ENCONTRAR ÚLTIMA MENSAGEM DO ASSISTANT
// ================================
let lastAssistantIndex = -1;

for (let i = messages.length - 1; i >= 0; i--) {
  if (messages[i].role === "assistant") {
    lastAssistantIndex = i;
    break;
  }
}

// ================================
// PEGAR RESPOSTAS NUMÉRICAS DO USER
// ================================
let respostas = "";

for (let i = lastAssistantIndex + 1; i < messages.length; i++) {
  const msg = messages[i];

  if (msg.role === "user") {
    const numeros = String(msg.text || "").replace(/\D/g, "");
    if (numeros) {
      respostas += numeros;
    }
  }
}

// ================================
// DEFINIR PREFIXO (REGRA NOVA)
// ================================
let prefixo = "";

if (serviceId) {
  prefixo = serviceId; // prioridade total
} else if (pieceId) {
  prefixo = pieceId;
}

// ================================
// RESULTADO FINAL
// ================================
const respostasConcatenadas = prefixo + respostas;

// ================================
// OUTPUT
// ================================
return [
  {
    json: {
      ...$json,
      respostas_concatenadas: respostasConcatenadas,
      total_respostas: respostasConcatenadas.length,
    },
  },
];

const items = $input.all();

// ================================
// CONFIG
// ================================
const SLOT_MINUTES = 30;

const PERIODOS = [
  { start: "07:00", end: "11:00" },
  { start: "13:00", end: "18:00" },
];

// ================================
// HELPERS
// ================================
function timeToMinutes(timeStr) {
  const [h, m] = String(timeStr).split(":").map(Number);
  return (h * 60) + m;
}

function minutesToTime(minutes) {
  const h = Math.floor(minutes / 60);
  const m = minutes % 60;
  return String(h).padStart(2, "0") + ":" + String(m).padStart(2, "0");
}

function extractTime(value) {
  if (!value) return null;

  // Se já vier como "07:30"
  if (/^\d{2}:\d{2}$/.test(String(value))) {
    return String(value);
  }

  // Se vier ISO tipo "2026-03-24T07:30:00.000Z"
  const str = String(value);
  const match = str.match(/T(\d{2}:\d{2})/);
  if (match) return match[1];

  return null;
}

// ================================
// HORÁRIOS OCUPADOS
// ================================
// Ajuste aqui o nome do campo que vem do Airtable
// Ex.: data_hora, horario, slot, start_time...
const occupiedSlots = items
  .map(item => {
    const json = item.json || {};
    return (
      extractTime(json.horario) ||
      extractTime(json.data_hora) ||
      extractTime(json.slot) ||
      extractTime(json.start_time)
    );
  })
  .filter(Boolean);

// Para busca rápida
const occupiedSet = new Set(occupiedSlots);

// ================================
// GERA TODOS OS SLOTS POSSÍVEIS
// ================================
const availableSlots = [];

for (const periodo of PERIODOS) {
  let current = timeToMinutes(periodo.start);
  const end = timeToMinutes(periodo.end);

  while (current < end) {
    const slot = minutesToTime(current);

    if (!occupiedSet.has(slot)) {
      availableSlots.push({
        horario: slot,
        periodo: `${periodo.start}-${periodo.end}`,
      });
    }

    current += SLOT_MINUTES;
  }
}

// ================================
// OUTPUT
// ================================
return availableSlots.map(slot => ({
  json: slot,
}));

