  preferencia_data = "HOJE";
  data_desejada = formatDateLocal(now);
} else if (opcao === "AMANHA" || opcao === "2") {
  preferencia_data = "AMANHA";
  data_desejada = formatDateLocal(addDays(now, 1));
} else if (opcao === "OUTRA_DATA" || opcao === "3") {
  preferencia_data = "OUTRA_DATA";

  if (dataManual) {
    data_desejada = parseBRDate(dataManual);
  } else {
    precisa_pedir_data = true;
  }
}

// =====================================================
// OUTPUT
